sql:
SELECT DISTINCT la.authority_name
FROM health_statistics hs
INNER JOIN local_authorities la ON hs.local_authority_id = la.local_authority_id;

external_knowledge:
- "Large populations" refers to wards with more than 50,000 inhabitants; 
- "Most reliable statistics" are determined by the highest data quality score for each area and gender;
- "Recorded access" implies that there is at least one log entry for the statistic.
